using System.Windows.Controls;
using System.Windows.Threading;
using MarketDataCollector.Ui.Services;
using MarketDataCollector.Contracts;

namespace MarketDataCollector.Wpf.Views;

public partial class DashboardPage : Page
{
    private readonly ICollectorService _collectorService;
    private readonly IStatusService _statusService;
    private readonly ISymbolService _symbolService;
    private readonly IMetricsService _metricsService;
    private readonly ILogService _logService;
    private readonly DispatcherTimer _refreshTimer;
    private long _previousPublished;
    private bool _isCollectorPaused;

    public DashboardPage(
        ICollectorService collectorService,
        IStatusService statusService,
        ISymbolService symbolService,
        IMetricsService metricsService,
        ILogService logService)
    {
        InitializeComponent();
        _collectorService = collectorService;
        _statusService = statusService;
        _symbolService = symbolService;
        _metricsService = metricsService;
        _logService = logService;

        _refreshTimer = new DispatcherTimer { Interval = TimeSpan.FromSeconds(2) };
        _refreshTimer.Tick += RefreshTimer_Tick;
        _refreshTimer.Start();
    }

    private async void RefreshTimer_Tick(object? sender, EventArgs e)
    {
        var status = await _statusService.GetStatusAsync();
        var rate = (status.Published - _previousPublished) / 2.0;

        PublishedCount.Text = FormatNumber(status.Published);
        EventRateLabel.Text = $"{rate:F1}/s";
        DroppedCount.Text = FormatNumber(status.Dropped);

        var brush = (System.Windows.Media.Brush)FindResource(
            status.IsHealthy ? "HealthyBrush" : "UnhealthyBrush");
        StatusIndicator.Fill = brush;

        _previousPublished = status.Published;
    }

    private async void StartCollector_Click(object sender, System.Windows.RoutedEventArgs e)
    {
        try
        {
            await _collectorService.StartAsync();
            _isCollectorPaused = false;
            StartButton.IsEnabled = false;
            StopButton.IsEnabled = true;
        }
        catch (Exception ex)
        {
            _logService.LogError($"Failed to start: {ex.Message}");
            System.Windows.MessageBox.Show(ex.Message);
        }
    }

    private string FormatNumber(long value) =>
        value >= 1_000_000 ? $"{value / 1_000_000.0:F1}M" :
        value >= 1_000 ? $"{value / 1_000.0:F1}K" :
        value.ToString();
}
