using System.Threading.Channels;
using Microsoft.Extensions.Logging;

namespace MarketDataCollector.Pipeline;

public class BatchFlushService : IAsyncDisposable
{
    private readonly Channel<MarketEvent> _channel;
    private readonly IStorageSink _sink;
    private readonly ILogger<BatchFlushService> _logger;
    private readonly int _batchSize = 100;
    private Task? _flushLoop;

    public BatchFlushService(IStorageSink sink, ILogger<BatchFlushService> logger)
    {
        _channel = Channel.CreateUnbounded<MarketEvent>();
        _sink = sink;
        _logger = logger;
    }

    public async Task StartAsync(CancellationToken ct)
    {
        _flushLoop = Task.Run(async () =>
        {
            var batch = new List<MarketEvent>();
            await foreach (var evt in _channel.Reader.ReadAllAsync())
            {
                batch.Add(evt);
                if (batch.Count >= _batchSize)
                {
                    _logger.LogDebug($"Flushing batch of {batch.Count} events");
                    foreach (var item in batch.ToList())
                    {
                        await _sink.WriteAsync(item);
                    }
                    batch.Clear();
                }
            }
        });
    }

    public async ValueTask DisposeAsync()
    {
        _channel.Writer.Complete();
        if (_flushLoop != null)
            _flushLoop.Wait();
    }
}
