using Microsoft.Extensions.Options;

namespace MarketDataCollector.Domain.Collectors;

public class BackfillOrchestrator
{
    private readonly IOptions<BackfillSettings> _settings;
    private readonly IEnumerable<IBackfillProvider> _providers;
    private readonly IStorageSink _sink;
    private readonly ILogger<BackfillOrchestrator> _logger;

    public BackfillOrchestrator(
        IOptions<BackfillSettings> settings,
        IEnumerable<IBackfillProvider> providers,
        IStorageSink sink,
        ILogger<BackfillOrchestrator> logger)
    {
        _settings = settings;
        _providers = providers;
        _sink = sink;
        _logger = logger;
    }

    public async Task BackfillAsync(string symbol, DateTime from, DateTime to)
    {
        foreach (var provider in _providers)
        {
            try
            {
                var data = await provider.FetchHistoricalAsync(symbol, from, to);
                foreach (var evt in data)
                {
                    await _sink.WriteAsync(evt);
                }
                _logger.LogInformation($"Backfill complete for {symbol} via {provider.Name}");
                return;
            }
            catch (Exception ex)
            {
                _logger.LogWarning($"Provider {provider.Name} failed: {ex.Message}");
            }
        }
        throw new Exception($"All providers failed for {symbol}");
    }
}
