using MarketDataCollector.FSharp.Types;
using System.Text.Json;

namespace MarketDataCollector.Ui.Services;

public class ProviderStatusService
{
    private readonly Dictionary<string, ProviderStatus> _cache = new();
    private readonly ILogger<ProviderStatusService> _logger;

    public ProviderStatusService(ILogger<ProviderStatusService> logger)
    {
        _logger = logger;
    }

    public void UpdateStatus(string providerId, ProviderStatus status)
    {
        _cache[providerId] = status;

        if (status.IsConnected)
        {
            _logger.LogInformation($"Provider {providerId} connected");
        }
    }

    public string GetStatusLabel(string providerId)
    {
        if (!_cache.TryGetValue(providerId, out var status))
            return "Unknown";

        return (ProviderStatus)status switch
        {
            var s when s.IsConnected => "Connected",
            var s when s.IsDisconnected => "Disconnected",
            _ => "Other"
        };
    }

    public string SerializeStatuses()
    {
        return JsonSerializer.Serialize(_cache);
    }
}
