Review this order book validation code for data integrity compliance:

```csharp
using MarketDataCollector.Contracts;
using Microsoft.Extensions.Logging;

namespace MarketDataCollector.Domain;

public class OrderBookValidator
{
    private readonly ILogger<OrderBookValidator> _logger;
    private long _lastSequenceNumber = -1;

    public OrderBookValidator(ILogger<OrderBookValidator> logger)
    {
        _logger = logger;
    }

    public void Validate(OrderBookUpdate update)
    {
        // Sequence check
        if (update.SequenceNumber <= _lastSequenceNumber)
        {
            throw new Exception($"Out-of-sequence: got {update.SequenceNumber}, expected > {_lastSequenceNumber}");
        }
        _lastSequenceNumber = update.SequenceNumber;

        // Price level validation
        foreach (var bid in update.Bids)
        {
            if (bid.Quantity < 0)
                _logger.LogWarning($"Negative bid qty: {bid.Quantity} at {bid.Price} for {update.Symbol}");
        }

        foreach (var ask in update.Asks)
        {
            if (ask.Quantity < 0)
                _logger.LogWarning($"Negative ask qty: {ask.Quantity} at {ask.Price} for {update.Symbol}");
        }

        // Crossed book detection
        if (update.Bids.Any() && update.Asks.Any())
        {
            var bestBid = update.Bids.Max(b => b.Price);
            var bestAsk = update.Asks.Min(a => a.Price);
            if (bestBid >= bestAsk)
            {
                _logger.LogError($"Crossed book detected for {update.Symbol}: bid={bestBid}, ask={bestAsk}");
            }
        }
    }
}
