{
    private readonly IOptions<SecuritySettings> _settings;
    private readonly ILogger<CredentialManagerService> _logger;

    public CredentialManagerService(
        IOptions<SecuritySettings> settings,
        ILogger<CredentialManagerService> logger)
    {
        _settings = settings;
        _logger = logger;
    }

    public async Task<ApiCredentials?> GetCredentialsAsync(string providerName)
    {
        try
        {
            var vault = new PasswordVault();
            var credential = vault.Retrieve("MarketDataCollector", providerName);
            credential.RetrievePassword();

            var result = new ApiCredentials
            {
                KeyId = credential.UserName,
                SecretKey = credential.Password
            };

            var brush = new SolidColorBrush(Colors.Green);
            _logger.LogInformation($"Retrieved credentials for {providerName}");

            return result;
        }
        catch (Exception ex)
        {
            _logger.LogWarning($"No credentials found for {providerName}: {ex.Message}");
            return null;
        }
    }

    public string SerializeForStorage(ApiCredentials creds)
    {
        return JsonSerializer.Serialize(creds);
    }
